// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../../../characters';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機震動。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是鬧鐘，是那種急促的、不講道理的震動，像有人反覆捏著他的手腕不放。顧言皺著眉，伸手在枕邊亂摸，指尖碰到冰涼的手機外殼，然後整個人像被抽掉了支撐一樣，從夢的邊緣滑進現實。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "07:05。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕上的數字很亮，亮到刺眼。宿舍廣播正用那種萬年不變的溫柔女聲播報校慶活動提醒，什麼「百年校史展全天開放」、「歡迎校友與家長蒞臨」，每個字都像提前寫好的劇本，不會因為聽的人心情不好就改一個字。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)又是校慶。", background: "chapter_1/ch1_act1_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把手机扣回枕邊，翻了個身，面對牆壁。上鋪的同學已經不在了，大概一早就跑去幫忙佈置會場。整間寢室只剩下他一個人，和窗外那片灰濛濛的雨聲。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鳴海高中靠山近海，天氣好的時候能從宿舍窗戶看見遠處的灰色海面，今天連海都看不見，只有雨。細細的、不間斷的雨，從昨天下到現在，像有人忘了關水龍頭。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言坐起來。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "動作很慢，像一具剛解凍的木偶。他揉了揉眼睛，感覺喉嚨裡有一種奇怪的乾澀，像吸過煙，又不完全是煙的味道——更像是什麼東西燒過之後殘留的焦味，黏在呼吸道內壁上，摳不掉。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)大概是昨晚沒睡好。", background: "chapter_1/ch1_act1_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他低頭看了看自己的手。右手指尖有一種殘留的觸感，像剛抓過什麼冰冷的金屬東西——欄杆？扶手？他說不上來。左手掌心也怪怪的，有種被塞進東西的錯覺，壓感還在，但手裡什麼都沒有。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "耳邊似乎還殘留一聲相機快門。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很輕，很短，像一根針戳進腦子裡又抽走。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)做夢了吧。", background: "chapter_1/ch1_act1_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他記得自己做了夢。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "夢的內容零零碎碎，像被揉爛的紙團，怎麼也攤不平。他只記得幾個畫面：暴雨——不是窗外這種安靜的細雨，而是像瀑布一樣傾瀉的暴雨，打在鐵皮屋頂上震耳欲聾。禮堂後台的燈忽明忽暗，像有人在開關那裡反覆拉扯。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後是一隻手。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一隻女生的手，把一個很小、很冰的東西塞進他的掌心。他看不清對方的臉，只感覺到她的手指很冷，像剛從冰水裡撈出來，指尖有點濕。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她開口了。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.FemaleVoice, character: "女聲", dialogue: "不要只⋯⋯", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "夢到這裡斷掉了。像被剪斷的錄影帶，後面的畫面全部消失，只剩下一片空白和耳鳴。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不要只什麼？不要只⋯⋯不要只是一場夢？不要只是嚇唬我？後面是什麼？", background: "chapter_1/ch1_act1_s0", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他搖了搖頭，把這些碎片趕出腦子。夢就是夢，沒有道理可講，越想越亂。", background: "chapter_1/ch1_act1_s0" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳踩到拖鞋的時候，地板傳來一陣涼意，他哆嗦了一下，起身走到洗手台前。水龍頭打開，冷水淋在手上，那種冰冷的金屬殘留感終於慢慢褪去。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他抬頭看了一眼窗外。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "灰色。全是灰色。天空是灰的，海面是灰的，遠處的鐘樓在雨霧裡只剩下一個模糊的輪廓，像一根插在霧裡的斷骨。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "鐘樓。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "看到它的瞬間，顧言的胃裡翻了一下。不是恐懼，比較像是本能的排斥。鐘樓是鳴海高中最老的建築，平常不開放，學生之間流傳著各種鬼故事。但那些故事都不是重點。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)重點是十年前。重點是南翼樓。重點是父親。", background: "chapter_1/ch1_act1_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十年前，鳴海高中南翼樓發生火災。官方結論是「校友顧某涉嫌人為縱火」。那個「顧某」，就是他的父親，顧澤。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言七歲那年，父親被帶走。之後他跟著外婆長大，輾轉幾個城市，最後因為戶籍關係回到鳴海高中就讀。他不知道這算不算命運的玩笑——讓縱火犯的兒子回到縱火現場，在同一片天空下長大。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他已經學會了一種生存技能：在被議論之前，先讓自己變得透明。不參加聚會，不主動社交，不在課堂上發言超過三句話。別人看見他會壓低聲音，他就假裝沒聽見。有人拿父親的事開玩笑，他就冷冷地回一句，然後走開。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)反正今天校慶，大家都在忙，不會有人注意我。撐過今天就好了。", background: "chapter_1/ch1_act1_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他關上水龍頭，用袖子擦了擦臉。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "洗手台上方有一面鏡子，他看見鏡子裡的自己：頭髮亂翹，眼下有淡淡的青黑，嘴唇乾裂，整個人看起來像沒充飽電的手機——還能開機，但隨時可能自動關機。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "帥。", background: "chapter_1/ch1_act1_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他對鏡子裡的自己說了一個字，語氣毫無起伏。不是自嘲，比較像是一種確認——確認這個人還在。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊上傳來腳步聲和笑聲，有同學已經出發去幫忙了。顧言拿起毛巾掛回架子上，正準備回房間換衣服。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機又震了。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是鬧鐘，是訊息。07:12。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他猶豫了一下，還是拿起了手機。一則來自陌生號碼的簡訊，沒有署名，號碼也查不到任何通訊軟體帳號。內容只有一行：", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "今晚 22:22，鐘樓會停電。不要上去。不要把相機交給任何大人。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: "chapter_1/ch1_act1_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)又來了。", background: "chapter_1/ch1_act1_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把訊息反覆看了兩遍，臉上沒有任何表情變化。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)鐘樓。又是鐘樓。", background: "chapter_1/ch1_act1_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他按下刪除。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "拇指停在螢幕上方的確認鍵，沒有按下去。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不要把相機交給任何大人。", background: "chapter_1/ch1_act1_s1", portrait: "顧言/base" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我根本沒有相機。", background: "chapter_1/ch1_act1_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這句話不對勁。前面那句「22:22 鐘樓會停電」像是惡作劇，像是那些喜歡拿火災舊案嚇他的人會編出來的東西。但「相機」這兩個字太具體了，不像隨手打出的玩笑。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "而且為什麼是「任何大人」？不是「任何人」，是「任何大人」。這個措辭帶著一種很奇怪的警惕，像是在警告他：不要相信大人。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯算了。", background: "chapter_1/ch1_act1_s1", portrait: "顧言/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他鬆開了手。拇指離開確認鍵，訊息還在。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機螢幕暗下去的瞬間，他看見自己的倒影。一張沒什麼表情的臉，眉心有一條很深的皺紋，那是從國中就開始有的，現在已經壓不平了。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊上的腳步聲越來越多，有人經過他的寢室門口，腳步頓了一下，然後加快離開。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "隔壁寢室的張昊從門口探了半個頭，瞄了一眼顧言手上的手機，咧嘴笑了。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.ZhangHao, character: "張昊", dialogue: "又有人約你去鬼樓？你爸以前是不是也去過那裡？", background: "chapter_1/ch1_act1_s1", portrait: "張昊/base" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的臉什麼都沒變。他把手機塞進口袋，看了張昊一眼，沒有回答。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "張昊被那個眼神盯了一下，笑容僵了半秒，縮回頭，腳步聲很快消失了。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有回頭。他拉開衣櫃，拿出一套乾淨的校服。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "窗外，雨還在下。鐘樓還站在雨霧裡。廣播裡的校慶提醒切了一段天氣預報，播音員說海上颱風警報已經發布，預計晚間影響本地區。", background: "chapter_1/ch1_act1_s1" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不知道的是，這將是他第一次也是最後一次醒來時，還能把一切都當成惡作劇。", background: "chapter_1/ch1_act1_s1" },
];
